import React from 'react';
import { Navbar as BNavbar, Nav, Container, Badge } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

function NavigationBar({ cartCount = 0, onNavigate, currentPage }) {
  const { user, logout } = useAuth();

  return (
    <BNavbar bg="dark" variant="dark" expand="lg" sticky="top">
      <Container>
        <BNavbar.Brand 
          style={{ cursor: 'pointer' }} 
          onClick={() => onNavigate && onNavigate('search')}
        >
          <span className="logo-container">
            <span className="logo-image">
              <img 
              src="/images/logo.ico" 
              alt="AutoParts" 
              style={{ 
                width: 40, 
                height: 40, 
                borderRadius: 8,
                background: 'white',
                padding: 4,
                objectFit: 'contain'
              }}
              onError={(e) => {
                // Если картинка не загрузилась - показываем эмодзи
                e.target.style.display = 'none';
                e.target.parentNode.innerHTML = '<span style="font-size:1.5rem">🚗</span>';
              }}
               />
            </span>
            <span className="logo-text">AutoParts</span>
          </span>
        </BNavbar.Brand>
        
        <BNavbar.Toggle aria-controls="basic-navbar-nav" />
        
        <BNavbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
            <Nav.Link 
              active={currentPage === 'search'}
              onClick={() => onNavigate && onNavigate('search')}
            >
              🔍 Поиск
            </Nav.Link>
            
            <Nav.Link 
              active={currentPage === 'orders'}
              onClick={() => onNavigate && onNavigate('orders')}
            >
              📋 Заказы
            </Nav.Link>
            
            <Nav.Link 
              active={currentPage === 'customers'}
              onClick={() => onNavigate && onNavigate('customers')}
            >
              👥 Клиенты
            </Nav.Link>
          </Nav>
          
          <Nav>
            <Nav.Item className="text-light d-flex align-items-center me-3">
              <small style={{ opacity: 0.8 }}>{user?.fullName} • {user?.role}</small>
            </Nav.Item>
            <Nav.Link onClick={logout} style={{ color: '#ff6b6b' }}>
              🚪 Выйти
            </Nav.Link>
          </Nav>
        </BNavbar.Collapse>
      </Container>
    </BNavbar>
  );
}

export default NavigationBar;
